package com.practice.visual.controller;
import com.practice.common.*;import com.practice.visual.entity.*;import com.practice.visual.repository.*;import com.practice.visual.service.*;import org.springframework.data.jpa.repository.JpaRepository;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/screens") class ScreenController extends CrudController<DashboardScreen>{ final ScreenService screens; ScreenController(DashboardScreenRepo r, CrudService<DashboardScreen> c, ScreenService screens){super(r,c);this.screens=screens;} @PostMapping("/{id}/publish") ApiResponse<DashboardScreen> pub(@PathVariable Long id){return ApiResponse.ok(screens.publish(id));} }
@RestController @RequestMapping("/api/video-devices") class VideoDeviceController extends CrudController<VideoDevice>{ VideoDeviceController(VideoDeviceRepo r, CrudService<VideoDevice> c){super(r,c);} }
@RestController @RequestMapping("/api/video-streams") class VideoStreamController extends CrudController<VideoStreamProxy>{ VideoStreamController(VideoStreamProxyRepo r, CrudService<VideoStreamProxy> c){super(r,c);} }
@RestController @RequestMapping("/api/video-alarm-tasks") class VideoAlarmTaskController extends CrudController<VideoAlarmTask>{ VideoAlarmTaskController(VideoAlarmTaskRepo r, CrudService<VideoAlarmTask> c){super(r,c);} }
abstract class CrudController<T extends BaseEntity>{ final JpaRepository<T,Long> repo; final CrudService<T> service; CrudController(JpaRepository<T,Long> repo,CrudService<T> service){this.repo=repo;this.service=service;} @GetMapping ApiResponse<List<T>> list(@RequestParam(required=false) String keyword){return ApiResponse.ok(service.list(repo,keyword));} @GetMapping("/{id}") ApiResponse<T> get(@PathVariable Long id){return ApiResponse.ok(service.get(repo,id));} @PostMapping ApiResponse<T> create(@RequestBody T body){return ApiResponse.ok(service.create(repo,body));} @PutMapping("/{id}") ApiResponse<T> update(@PathVariable Long id,@RequestBody T body){return ApiResponse.ok(service.update(repo,id,body));} @DeleteMapping("/{id}") ApiResponse<Boolean> delete(@PathVariable Long id){return ApiResponse.ok(service.delete(repo,id));} @PostMapping("/{id}/toggle") ApiResponse<T> toggle(@PathVariable Long id){return ApiResponse.ok(service.toggle(repo,id));} }
